// Assign deterministic likes/dislikes to demo posts
const demoLikes = [24, 18, 31, 42, 15, 27, 19, 38, 12, 22, 33, 16, 29, 21, 26, 35, 14, 20, 37, 23, 17, 41, 25, 28, 11, 34, 19, 13, 39, 22];
const demoDislikes = [3, 2, 4, 6, 1, 3, 2, 5, 1, 3, 4, 2, 3, 2, 3, 5, 1, 2, 4, 3, 2, 5, 3, 4, 1, 4, 2, 1, 5, 3];
insiderPosts.forEach((post, i) => {
  post.likes = demoLikes[i] ?? 10;
  post.dislikes = demoDislikes[i] ?? 2;
});

const typedPosts = insiderPosts as InsiderPost[];

export function getInsiderPostsByCompany(companyId: string): InsiderPost[] {
  return typedPosts.filter((p) => p.companyId === companyId);
}

export function getInsiderPost(postId: string): InsiderPost | undefined {
  return typedPosts.find((p) => p.id === postId);
}
